{"code": "import os
import re

# 定义函数，用于提取类和方法名
def extract_class_and_method_names(directory):
    class_and_method_names = []
    for root, dirs, files in os.walk(directory):
        for file in files:
            if file.endswith('.py'):
                with open(os.path.join(root, file), 'r', encoding='utf-8') as f:
                    content = f.read()
                    # 使用正则表达式匹配类和方法名
                    class_and_method_names.extend(re.findall(r'class\s+(\w+)\s+(:|\{)', content))
                    class_and_method_names.extend(re.findall(r'def\s+(\w+)\s*\((.*?)\)', content))
    return class_and_method_names

# 调用函数并打印结果
if __name__ == '__main__':
    directory = 'core'
    class_and_method_names = extract_class_and_method_names(directory)
    print(class_and_method_names)"}

